const input = $input.first().json;
const now = new Date();
const dateStr = now.toISOString().slice(0, 10).replace(/-/g, '');
const seq = String(Math.floor(Math.random() * 999) + 1).padStart(3, '0');

return [{
  json: {
    id: `DL-${dateStr}-${seq}`,
    timestamp: now.toISOString(),
    source_workflow: input.source_workflow || 'unknown',
    source_node: input.source_node || 'unknown',
    error_type: input.error_type || 'UNKNOWN',
    error_message: input.error_message || input.message || 'No error message provided',
    original_payload: input.original_payload || input.body || {},
    retry_count: input.retries_exhausted || input.retry_count || 0,
    status: 'pending_review'
  }
}];
